import{_ as n}from"./nyalra_kb-7135827b.js";import{_ as s}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as i,X as p,Y as _,Z as e,$ as t,a1 as o,a2 as m,a0 as d,C as a}from"./framework-91490e6a.js";const f={},u=e("figure",null,[e("img",{src:n,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/37a2eb9b23e3cc3b7f900292ad6dc306.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>我对格斗游戏的了解仅仅是「一定程度上接触过」，所以不知道详细情况，但最近两名格斗游戏玩家之间的Twitter争论引起了我的兴趣。后来，他们通过实际直播对战来决定了谁对谁错。我觉得这很健全，很羡慕。</p><p>网络上的争论通常都很无益，因为很少有明确的胜负，究竟哪一方是正确的几乎无法确定。人们在回复和争论中不断互相指责和挑刺，最终会陷入无休止的争吵，而没有实质意义。最糟糕的情况下，有时会由场上气氛来决定谁是失败者，这也可能仅仅是多数人的意见。即使有人在激烈的争议中提出了合理的观点，如果大多数人只是想搅乱局面，那些有理有据的观点也会被「这位信徒到底在拥护什么？」地一起抛弃。在这个世界里，纷争是不会消失的。</p><p>然而，格斗游戏不同。胜负是明显可见的。通过突然进行的10局胜负比赛，单纯的口舌之争也会从「赛博摔跤」变成「面对比赛的玩家之间的战前垃圾话」，不仅让参与者和观众激动，也使这些无谓的争吵变成一场「职业摔跤」表演，变成了一场娱乐活动。这真是太棒了。</p><p>这场比赛的问题在于，即使对方更强，但实际上也与讨论的问题无关。比如，在这次事件中，一个玩家在一条推特中提到了新作的相关情况，然后在回复中突然被卷入争论（甚至被挑衅），在激烈的辩论中，决定进行一场实际的比赛。结果是「被卷入争论的一方」输了，但事实上，最初触发争议的玩家只是简单地发表了一条与新作相关的评论，而且在这条评论下也有不少人表示支持。然而，现在无论发端是谁都已经不重要，最终大家只关心比赛的胜负。</p><p>虽说如此，如前所述，反正互联网上的争论通常很少能解决，不如像这样大家总的来说都觉得很有趣，热热闹闹的。因此，可以「通过游戏来决定谁对谁错」的系统本身也是好事，这也让人感到羡慕。实力就是这样，它有着让人无法忽视的力量。无论是格斗游戏玩家还是体育运动员，不管嘴巴和态度有多么恶劣，也会有很多人被他们的实力所吸引而路转粉。这么明确的事情并不常见。</p><p>我读美食漫画时也有同感。即使关于食物的讨论可能会变得很激烈，但最终胜负总是在美食对决中决出，大家也都会互相承认。这个世界上的很多事情，如果能够更加明确地通过公平的评判来决定胜负，可能会更加容易理解，但这也可能导致一个残酷而局促的世界，所以很难。在这方面，无论走到哪里，都能够通过「在擂台上进行比赛」来解决争端的游戏玩家太酷了。顺便一提，我对『花仙子方块（パネポン）』的对战有点自信。如果有人对我的这篇文章不满，就和我一起在花仙子方块中决一胜负吧！！！</p><hr><p><img src="'+s+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/e16616f0f29f862f5e7f281fc263486a.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【Build驱动器和Evolt驱动器】这是出现在『假面骑士Build』中的变身腰带。选择「ビルドドライバー（Build Driver）」而不是「ビルドライバー（BuilDriver）」的名称真好啊。另外，我非常喜欢「Evolt Driver」。光是转动摇杆，就可以听到威风凛凛的声音和背景音乐，任何人都可以简单地感受到这是最终BOSS，这太棒了。</p></blockquote>',10);function g(v,x){const r=a("ExternalLinkIcon"),l=a("RouterLink");return i(),p("div",null,[_(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第32回／うるせえ、ゲームで勝負だ！！！"),o(r)])]),e("blockquote",null,[k,e("p",null,[o(l,{to:"/posts/Translate/nyalra_kb_31.html"},{default:m(()=>[t("【奈亚拉面壁自语】第31回｜游戏的本质【230620】")]),_:1})])]),b])}const E=c(f,[["render",g],["__file","nyalra_kb_32.html.vue"]]);export{E as default};
